from collections import defaultdict

class Solution(object):
    def remainingMethods(self, n, k, invocations):
        # Build directed graph
        graph = defaultdict(list)
        for a, b in invocations:
            graph[a].append(b)

        # DFS from k to find all suspicious methods
        suspicious = set()
        stack = [k]
        while stack:
            node = stack.pop()
            if node in suspicious:
                continue
            suspicious.add(node)
            for nb in graph[node]:
                stack.append(nb)

        # Check if any non-suspicious method invokes a suspicious one
        for a, b in invocations:
            if a not in suspicious and b in suspicious:
                # Cannot remove; return all methods
                return list(range(n))

        # Safe to remove all suspicious methods
        return [i for i in range(n) if i not in suspicious]
